import React from "react";

const projects = [
  {
    title: "Non-Electrical Solar Tracker",
    description:
      "A simple solar tracker idea that follows the sun without a complicated electrical setup. The goal is to keep it low-cost, easy to understand, and easy to maintain.",
  },
  {
    title: "BESS Integration with Solar",
    description:
      "A project that combines solar power with battery storage. It helps store extra energy during the day and use it later when needed.",
  },
  {
    title: "Remote Operated Accelerator System",
    description:
      "A remote-operated system made for smooth and safe control. The focus is on easy use, reliable operation, and practical design.",
  },
  {
    title: "Li-Fi Communication System",
    description:
      "A Li-Fi project that sends data using light instead of radio waves. It is a simple and interesting way to explore a new communication idea.",
  },
];

function Projects() {
  return (
    <div className="section-shell">
      <div className="section-heading">
        <p className="eyebrow">Projects</p>
        <h2>Some projects I worked on</h2>
      </div>

      <div className="project-grid">
        {projects.map((project) => (
          <article className="project-card" key={project.title}>
            <h3>{project.title}</h3>
            <p>{project.description}</p>
          </article>
        ))}
      </div>
    </div>
  );
}

export default Projects;
